{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-three-step-priority-chain-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的 Trim Heater 及其进出口物流生成候选编辑提案，优先处理出口物流断开、进料规格缺失和加热器出口温度目标缺失这三类直接诊断问题。",
      "issues": [
        {
          "title": "Heater Outlet 缺少下游消费者或导出汇",
          "detail": "诊断指出 product-7 未连接到任何下游 consumer 或 export sink，且最新快照显示拓扑无效；该问题会阻止流程图形成有效拓扑。",
          "severity": "error",
          "citations": [
            "diag-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        },
        {
          "title": "Heater Feed 缺少温度和流量规格",
          "detail": "诊断指出 feed-7 当前仅给出压力规格，缺少温度和流量规格；这些入口边界条件不足以支撑局部单元求解。",
          "severity": "error",
          "citations": [
            "diag-2",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "Trim Heater 缺少出口温度控制目标",
          "detail": "heater-3 已配置为 outlet_temperature 控制模式，但配置中未给出 outlet temperature target，与当前控制模式不完整的诊断一致。",
          "severity": "error",
          "citations": [
            "diag-3",
            "flowdoc-unit-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Heater Outlet 添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "product-7"
          },
          "rationale": "product-7 被诊断为未连接到任何下游消费者或导出汇。由于当前请求未提供可连接的具体下游单元或导出对象，建议仅添加一个待确认的连接占位，避免凭空创建拓扑对象或执行高风险重连。",
          "patch": {
            "connection_placeholder": {
              "downstream_consumer_or_export_sink_required": true,
              "note": "选择或创建下游 consumer/export sink 后再确认连接。"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Heater Feed 补充温度和流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-7"
          },
          "rationale": "feed-7 当前仅包含 pressure_kpa: 215，而诊断明确指出缺少 temperature 和 flow rate。建议添加待用户填写的规格占位，不推断具体数值。",
          "patch": {
            "spec_placeholders": {
              "temperature_c": {
                "required": true,
                "reason": "STREAM_SPEC_MISSING"
              },
              "flow_rate": {
                "required": true,
                "reason": "STREAM_SPEC_MISSING"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Trim Heater 添加出口温度目标占位",
          "target": {
            "type": "unit",
            "id": "heater-3"
          },
          "rationale": "heater-3 的 control_mode 为 outlet_temperature，但诊断指出缺少出口温度控制目标。由于出口物流 product-7 已存在 temperature_c: 155，可作为候选参考值；仍需用户确认是否应作为加热器目标温度写入单元参数。",
          "patch": {
            "parameter_placeholders": {
              "outlet_temperature_target_c": {
                "candidate_value": 155,
                "source": "product-7.specs.temperature_c",
                "requires_user_confirmation": true,
                "reason": "UNIT_PARAMETER_INCOMPLETE"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "flowdoc-stream-2"
          ]
        }
      ],
      "confidence": 0.86
    }
  ]
}
